import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/Survey.css';

function Survey() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    name: '',
    age: '',
    sex: '',
    smoking: '',
    allergy: ''
  });
  const [error, setError] = useState('');

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    // Get user_id from localStorage
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      setError('User session expired. Please sign up again.');
      return;
    }

    // Підготовка даних для надсилання на сервер
    // Переконуємося, що всі дані мають правильний тип
    const dataToSubmit = {
      user_id: parseInt(user_id, 10), // Перетворення на число
      name: formData.name.trim(),
      age: parseInt(formData.age, 10), // Перетворення на число
      sex: formData.sex,
      smoking: formData.smoking === 'yes' ? 1 : 0, // Переконуємося, що це число
      allergy: formData.allergy.trim()
    };

    // Перевірка коректності даних перед надсиланням
    if (isNaN(dataToSubmit.age) || dataToSubmit.age <= 0 || dataToSubmit.age > 120) {
      setError('Please enter a valid age between 1 and 120');
      return;
    }

    try {
      const response = await fetch('http://localhost:5000/api/survey', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(dataToSubmit),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || 'An error occurred. Please try again.');
      }

      navigate('/dashboard');
    } catch (err) {
      console.error('Survey submission error:', err);
      setError(err.message);
    }
  };

  return (
    <div className="survey-container">
      <div className="survey-form">
        <h2>Additional Information</h2>
        {error && <div className="error-message">{error}</div>}
        <form onSubmit={handleSubmit}>
          <div className="survey-form-group">
            <input
              type="text"
              name="name"
              value={formData.name}
              onChange={handleChange}
              required
              placeholder=" "
            />
            <label>Name</label>
          </div>

          <div className="survey-form-group">
            <input
              type="number"
              name="age"
              value={formData.age}
              onChange={handleChange}
              required
              min="0"
              max="120"
              placeholder=" "
            />
            <label>Age</label>
          </div>

          <div className="survey-form-group">
            <select
              name="sex"
              value={formData.sex}
              onChange={handleChange}
              required
              placeholder=" "
            >
              <option value="">Select Gender</option>
              <option value="male">Male</option>
              <option value="female">Female</option>
            </select>
            <label>Gender</label>
          </div>

          <div className="survey-form-group">
            <div className="smoking-section">
              <p className="smoking-label">Smoking Status</p>
              <div className="radio-group">
                <label>
                  <input
                    type="radio"
                    name="smoking"
                    value="yes"
                    checked={formData.smoking === "yes"}
                    onChange={handleChange}
                    required
                  />
                  <span>Yes</span>
                </label>
                <label>
                  <input
                    type="radio"
                    name="smoking"
                    value="no"
                    checked={formData.smoking === "no"}
                    onChange={handleChange}
                  />
                  <span>No</span>
                </label>
              </div>
            </div>
          </div>

          <div className="survey-form-group">
            <input
              type="text"
              name="allergy"
              value={formData.allergy}
              onChange={handleChange}
              required
              placeholder=" "
            />
            <label>Allergies</label>
            <div className="allergies-hint">
              Please list your allergies separated by commas. Common allergies: pollen, dust, mold, pets, food. Write "none" if you don't have any allergies.
            </div>
          </div>

          <div className="button-group">
            <button type="submit" className="submit-button">
              Submit
            </button>
            <button 
              type="button" 
              className="clear-button"
              onClick={() => setFormData({ name: '', age: '', sex: '', smoking: '', allergy: '' })}
            >
              Clear form
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default Survey;
